/* == EXEMPLE =======================================
 * Struct Config partagee : port + host
 * ================================================= */
typedef struct { int port; char host[32]; } Config;
void example_shm_struct(void) {
    int fd = shm_open("/kf_ex_cfg", O_CREAT|O_RDWR, 0644);
    ftruncate(fd, sizeof(Config));
    Config *c = (Config *)mmap(NULL, sizeof(Config), PROT_READ|PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);
    if (fork() == 0) { c->port = 8080; strncpy(c->host, "localhost", 31); _exit(0); }
    wait(NULL);
    printf("port=%d host=%s\n", c->port, c->host);
    munmap(c, sizeof(Config)); shm_unlink("/kf_ex_cfg");
}
